import type { ReactNode } from 'react';

export type ErrorProps = ErrorPropsWithDefaultActions | ErrorPropsExceptDefault;

export interface ErrorPropsBase {
	title: string;
	subtitle: string | ReactNode;
	image: ErrorImages | string;
	className?: string;
}

export interface ErrorPropsWithDefaultActions extends ErrorPropsBase {
	actions: 'default';
	defaultOnBack?: () => void;
	defaultOnRefresh?: () => void;
}

export interface ErrorPropsExceptDefault extends ErrorPropsBase {
	actions?: Exclude<'default', 'default'> | ReactNode;
	defaultOnBack?: never;
	defaultOnRefresh?: never;
}

export enum ErrorImages {
	error403,
	error404,
	error500,
	error502,
	error503,
	gear,
	radio,
}
